"""Recorded money lines — the authoritative source for downstream artifacts.

Loads the nightly export CSVs (charges, refund lines, payout lines) from
`exports/`. Per docs/accounting.md, these recorded lines — not recomputation
from order data — are what vendor statements, webhook notifications, and the
audit log must report.
"""
from __future__ import annotations

import csv
import re
from dataclasses import dataclass
from pathlib import Path

from libs.money import Money

EXPORTS_DIR = Path(__file__).resolve().parents[2] / "exports"

_MONTH_RE = re.compile(r"\d{4}-(0[1-9]|1[0-2])")


@dataclass(frozen=True)
class RecordedCharge:
    order_id: str
    charged_at: str  # ISO date, e.g. "2026-04-17"
    status: str  # "fulfilled" | "cancelled"
    amount: Money

    @property
    def month(self) -> str:
        return self.charged_at[:7]


@dataclass(frozen=True)
class RecordedRefundLine:
    order_id: str
    charged_at: str
    sku: str
    amount: Money

    @property
    def month(self) -> str:
        return self.charged_at[:7]


@dataclass(frozen=True)
class RecordedPayoutLine:
    order_id: str
    charged_at: str
    payee: str  # "platform" or a vendor
    amount: Money

    @property
    def month(self) -> str:
        return self.charged_at[:7]


@dataclass(frozen=True)
class RecordedLines:
    charges: list[RecordedCharge]
    refund_lines: list[RecordedRefundLine]
    payout_lines: list[RecordedPayoutLine]


def load_recorded_lines(exports_dir: Path = EXPORTS_DIR) -> RecordedLines:
    with (exports_dir / "charges.csv").open(newline="") as f:
        charges = [
            RecordedCharge(
                order_id=row["order_id"],
                charged_at=row["charged_at"],
                status=row["status"],
                amount=Money.from_cents(int(row["charged_cents"])),
            )
            for row in csv.DictReader(f)
        ]
    charged_at = {c.order_id: c.charged_at for c in charges}
    with (exports_dir / "refund_lines.csv").open(newline="") as f:
        refund_lines = [
            RecordedRefundLine(
                order_id=row["order_id"],
                charged_at=charged_at[row["order_id"]],
                sku=row["sku"],
                amount=Money.from_cents(int(row["amount_cents"])),
            )
            for row in csv.DictReader(f)
        ]
    with (exports_dir / "payout_lines.csv").open(newline="") as f:
        payout_lines = [
            RecordedPayoutLine(
                order_id=row["order_id"],
                charged_at=charged_at[row["order_id"]],
                payee=row["payee"],
                amount=Money.from_cents(int(row["amount_cents"])),
            )
            for row in csv.DictReader(f)
        ]
    return RecordedLines(charges=charges, refund_lines=refund_lines, payout_lines=payout_lines)


def validate_month(month: str) -> str:
    if not _MONTH_RE.fullmatch(month):
        raise ValueError(f"expected YYYY-MM month, got {month!r}")
    return month


def month_range(first: str, last: str) -> list[str]:
    """Inclusive list of YYYY-MM months from ``first`` to ``last``."""
    validate_month(first)
    validate_month(last)
    if first > last:
        raise ValueError(f"month range is empty: {first} > {last}")
    months = []
    year, month = int(first[:4]), int(first[5:7])
    while (current := f"{year:04d}-{month:02d}") <= last:
        months.append(current)
        year, month = (year, month + 1) if month < 12 else (year + 1, 1)
    return months

