import hashlib
import hmac
import json

from services.notifications.outbox import (
    build_events,
    load_subscriptions,
    sign_payload,
    write_outbox,
)
from services.statements.recorded import load_recorded_lines

EVENT_RANK = {
    "order.cancelled": 0,
    "order.fulfilled": 1,
    "payout.recorded": 2,
    "refund.recorded": 3,
}


def _sort_key(event, payload):
    party = payload.get("payee", payload.get("sku", ""))
    return (payload["charged_at"], payload["order_id"], EVENT_RANK[event], party)


def test_events_cover_all_recorded_lines_in_range():
    recorded = load_recorded_lines()
    events = build_events(recorded, "2026-04", "2026-06")
    fulfilled = sum(1 for c in recorded.charges if c.status == "fulfilled")
    cancelled = sum(1 for c in recorded.charges if c.status == "cancelled")
    counts = {}
    for event, _ in events:
        counts[event] = counts.get(event, 0) + 1
    assert counts == {
        "order.fulfilled": fulfilled,
        "order.cancelled": cancelled,
        "refund.recorded": len(recorded.refund_lines),
        "payout.recorded": len(recorded.payout_lines),
    }


def test_events_are_in_deterministic_delivery_order():
    events = build_events(load_recorded_lines(), "2026-04", "2026-06")
    keys = [_sort_key(event, payload) for event, payload in events]
    assert keys == sorted(keys)


def test_amounts_come_from_recorded_lines():
    recorded = load_recorded_lines()
    events = build_events(recorded, "2026-04", "2026-06")
    charged = {c.order_id: c for c in recorded.charges}
    for event, payload in events:
        if event in ("order.fulfilled", "order.cancelled"):
            assert payload["charged_cents"] == charged[payload["order_id"]].amount.to_cents()
        assert payload["charged_at"] == charged[payload["order_id"]].charged_at


def test_subset_range_writes_only_that_ranges_events():
    recorded = load_recorded_lines()
    q2 = build_events(recorded, "2026-04", "2026-06")
    april = build_events(recorded, "2026-04", "2026-04")
    assert april == [e for e in q2 if e[1]["charged_at"].startswith("2026-04")]
    assert april and len(april) < len(q2)


def test_outbox_files_filter_sign_and_reproduce(tmp_path):
    subscriptions = {s.id: s for s in load_subscriptions()}
    first = write_outbox("2026-04", "2026-06", out_dir=tmp_path / "a")
    second = write_outbox("2026-04", "2026-06", out_dir=tmp_path / "b")
    assert sorted(p.name for p in first) == sorted(f"{sid}.jsonl" for sid in subscriptions)
    for a, b in zip(first, second):
        assert a.read_bytes() == b.read_bytes()

    for path in first:
        subscription = subscriptions[path.stem]
        for line in path.read_text().splitlines():
            entry = json.loads(line)
            assert set(entry) == {"event", "payload", "signature"}
            assert entry["event"] in subscription.events
            body = json.dumps(entry["payload"], sort_keys=True, separators=(",", ":"))
            expected = hmac.new(
                subscription.secret.encode(), body.encode(), hashlib.sha256
            ).hexdigest()
            assert entry["signature"] == expected


